```typescript
import { setup, assign, sendTo } from 'xstate';

const worker = setup({
  types: {
    events: {} as { type: 'TASK'; id: number } | { type: 'DONE'; id: number },
  },
}).createMachine({
  id: 'worker',
  initial: 'idle',
  states: {
    idle: {
      on: {
        TASK: {
          actions: sendTo(
            ({ self }) => self._parent!,
            ({ event }) => ({ type: 'DONE' as const, id: event.id }),
          ),
        },
      },
    },
  },
});

export const coordinator = setup({
  types: {
    context: {} as { completed: number },
    events: {} as { type: 'RUN'; id: number } | { type: 'DONE'; id: number },
  },
  actors: { worker },
}).createMachine({
  id: 'coordinator',
  context: { completed: 0 },
  invoke: { src: 'worker', id: 'w' },
  on: {
    RUN: {
      actions: sendTo('w', ({ event }) => ({ type: 'TASK' as const, id: event.id })),
    },
    DONE: { actions: assign({ completed: ({ context }) => context.completed + 1 }) },
  },
});
```

```typescript
import { setup, assign, sendTo, type ActorRefFrom } from 'xstate';

const pinger = setup({
  types: { events: {} as { type: 'PING' } | { type: 'PONG' } },
}).createMachine({
  id: 'pinger',
  on: {
    PING: {
      actions: sendTo(({ self }) => self._parent!, { type: 'PONG' }),
    },
  },
});

export const parent = setup({
  types: {
    context: {} as { child: ActorRefFrom<typeof pinger> | null; pongs: number },
    events: {} as { type: 'START' } | { type: 'PING' } | { type: 'PONG' },
  },
  actors: { pinger },
}).createMachine({
  id: 'parent',
  context: { child: null, pongs: 0 },
  on: {
    START: {
      actions: assign({
        child: ({ spawn }) => spawn('pinger', { id: 'p' }),
      }),
    },
    PING: { actions: sendTo('p', { type: 'PING' }) },
    PONG: { actions: assign({ pongs: ({ context }) => context.pongs + 1 }) },
  },
});
```

The parent invokes or spawns a child actor and gets a handle it can target with `sendTo`. The child reaches its parent via `self._parent` and sends events back, which the parent handles in `on:`. Typing the child's events so the parent's union includes them keeps the bridge type-safe.

```typescript
