import { setup, assign, enqueueActions } from 'xstate';

export const cartMachine = setup({
  types: {
    context: {} as { total: number; coupon: string | null },
    events: {} as { type: 'ADD'; price: number } | { type: 'CHECK' },
  },
  guards: {
    bigSpender: ({ context }) => context.total >= 100,
  },
}).createMachine({
  id: 'cart',
  context: { total: 0, coupon: null },
  on: {
    ADD: {
      actions: enqueueActions(({ enqueue, check }) => {
        enqueue.assign({ total: ({ context, event }) => context.total + event.price });
        enqueue.raise({ type: 'CHECK' });
        if (check('bigSpender')) {
          enqueue.assign({ coupon: () => 'VIP10' });
        }
      }),
    },
    CHECK: {},
  },
});
