import { setup, enqueueActions } from 'xstate';

type Entry = { at: number; amount: number };

export const ledger = setup({
  types: {
    context: {} as { balance: number; audit: Entry[] },
    events: {} as { type: 'DEBIT'; amount: number } | { type: 'ALERT' },
  },
  guards: {
    wouldOverdraft: ({ context, event }) =>
      event.type === 'DEBIT' && context.balance - event.amount < 0,
  },
}).createMachine({
  id: 'ledger',
  context: { balance: 100, audit: [] },
  on: {
    DEBIT: {
      actions: enqueueActions(({ enqueue, check, event }) => {
        if (check('wouldOverdraft')) {
          enqueue.raise({ type: 'ALERT' });
          return;
        }
        enqueue.assign({ balance: ({ context }) => context.balance - event.amount });
        enqueue.assign({
          audit: ({ context }) => [...context.audit, { at: Date.now(), amount: event.amount }],
        });
      }),
    },
    ALERT: {},
  },
});
```

