}).createMachine({
  id: 'tabs',
  initial: 'visible',
  states: {
    visible: {
      initial: 'a',
      on: { HIDE: 'hidden' },
      states: {
        a: { on: { SELECT_B: 'b' } },
        b: {},
        last: { type: 'history', history: 'shallow' },
      },
    },
    hidden: { on: { SHOW: 'visible.last' } },
  },
});
```

