```typescript
import { setup, assign } from 'xstate';

export const timer = setup({
  types: {
    context: {} as { ticks: number; resets: number },
    events: {} as { type: 'TICK' } | { type: 'RESET' },
  },
}).createMachine({
  id: 'timer',
  initial: 'running',
  context: { ticks: 0, resets: 0 },
  states: {
    running: {
      entry: assign({ resets: ({ context }) => context.resets + 1 }),
      on: {
        TICK: {
          // Internal — no reenter, entry does not fire again.
          actions: assign({ ticks: ({ context }) => context.ticks + 1 }),
        },
        RESET: {
          // External self-transition — entry fires again.
          target: 'running',
          reenter: true,
          actions: assign({ ticks: () => 0 }),
        },
      },
    },
  },
});
```

Omit `target` (or target the same node without `reenter: true`) for internal transitions — entry/exit actions do not run again. Set `reenter: true` to fire entry/exit on the same state node.

```typescript
import { setup, assign } from 'xstate';

export const demo = setup({
  types: {
    context: {} as { entries: number; actions: number },
    events: {} as { type: 'BUMP' } | { type: 'RESTART' },
  },
}).createMachine({
  id: 'demo',
  initial: 'active',
  context: { entries: 0, actions: 0 },
  states: {
    active: {
      entry: assign({ entries: ({ context }) => context.entries + 1 }),
      on: {
        BUMP: {
          // internal: entry does NOT run again
          actions: assign({ actions: ({ context }) => context.actions + 1 }),
        },
        RESTART: {
          // external self-transition: entry DOES run again
          target: 'active',
          reenter: true,
        },
      },
    },
  },
});
```

Internal (default) self-transitions keep you in the same state without firing entry or exit actions — they're useful when an event only needs to mutate context. External self-transitions (`reenter: true`) re-fire entry and exit on the state node, which is handy for restarting timers or resetting per-entry side effects.

```typescript
import { setup, assign } from 'xstate';

export const search = setup({
  types: {
    context: {} as { query: string; debouncedAt: number },
    events: {} as { type: 'TYPE'; q: string } | { type: 'CLEAR' },
  },
}).createMachine({
  id: 'search',
  initial: 'active',
  context: { query: '', debouncedAt: 0 },
  states: {
    active: {
      entry: assign({ debouncedAt: () => Date.now() }),
      on: {
        TYPE: {
          // internal: update query without restarting the debounce timestamp
          actions: assign({ query: ({ event }) => event.q }),
        },
        CLEAR: {
          // external self-transition: entry fires, debouncedAt resets
          target: 'active',
          reenter: true,
          actions: assign({ query: () => '' }),
        },
      },
    },
  },
});
```

